long cur_batch, out_x, out_y, k_x, k_y, in_x, in_y;
const int32_t input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;

for (cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
{
    for (out_y = 0, in_y = -pad; out_y < out_tensor_dim; out_y++, in_y += stride)
    {
        long ker_y_start = MAX(0, in_y);
        long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);
        for (out_x = 0, in_x = -pad; out_x < out_tensor_dim; out_x++, in_x += stride)
        {
            long ker_x_start = MAX(0, in_x);
            long ker_x_end   = MIN(in_tensor_dim, in_x + ker_dim);
            long cur_ch = 0, vl = 0;

            long in_tensor_ch2 = in_tensor_ch;
            while(in_tensor_ch2 > 0)
            {
                // reset the max values
                vl = __riscv_vsetvl_e8m8(in_tensor_ch2);
                vint8m8_t vMax = __riscv_vmv_v_x_i8m8(0x80, vl);

                for(k_y = ker_y_start; k_y < ker_y_end; k_y++)
                {
                    for(k_x = ker_x_start; k_x < ker_x_end; k_x++)
                    {
                        const q7_t *in_ptr = in_tensor + (in_tensor_ch * (k_x + k_y * in_tensor_dim)) + cur_ch;
                        vint8m8_t vIn = __riscv_vle8_v_i8m8(in_ptr, vl);
                        vMax = __riscv_vmax(vIn, vMax, vl);
                    }
                }

                __riscv_vse8(out_tensor, vMax, vl);
                out_tensor += vl;
                cur_ch += vl;
                in_tensor_ch2 -= vl;
            }
        }
    }
    in_tensor += input_len;
}

