long cur_batch, out_x, out_y, k_x, k_y;
const int32_t input_len = in_tensor_dim * in_tensor_dim * in_tensor_ch;

for (cur_batch = 0; cur_batch < in_tensor_batch; cur_batch++)
{
    for (out_y = 0; out_y < out_tensor_dim; out_y++)
    {
        long in_y = (long)out_y * stride - pad;
        long ker_y_start = MAX(0, in_y);
        long ker_y_end   = MIN(in_tensor_dim, in_y + ker_dim);

        for (out_x = 0; out_x < out_tensor_dim - 1; out_x += 2)
        {
            /* Pixel A = out_x, Pixel B = out_x+1 */
            long in_x_a = (long)out_x * stride - pad;
            long in_x_b = (long)(out_x + 1) * stride - pad;

            long kx_start_a = MAX(0, in_x_a);
            long kx_end_a   = MIN(in_tensor_dim, in_x_a + ker_dim);
            long kx_start_b = MAX(0, in_x_b);
            long kx_end_b   = MIN(in_tensor_dim, in_x_b + ker_dim);

            long cur_ch = 0;
            long remaining = in_tensor_ch;
            q7_t *out_a = out_tensor + (long)(out_x) * in_tensor_ch;
            q7_t *out_b = out_tensor + (long)(out_x + 1) * in_tensor_ch;

            while (remaining > 0)
            {
                long vl = __riscv_vsetvl_e8m4(remaining);
                vint8m4_t vMaxA = __riscv_vmv_v_x_i8m4(-128, vl);
                vint8m4_t vMaxB = __riscv_vmv_v_x_i8m4(-128, vl);

                for (k_y = ker_y_start; k_y < ker_y_end; k_y++)
                {
                    const q7_t *row_base = in_tensor + (long)k_y * in_tensor_dim * in_tensor_ch + cur_ch;

                    for (k_x = kx_start_a; k_x < kx_end_a; k_x++)
                    {
                        const q7_t *ptrA = row_base + (long)k_x * in_tensor_ch;
                        vint8m4_t vInA = __riscv_vle8_v_i8m4(ptrA, vl);
                        vMaxA = __riscv_vmax(vInA, vMaxA, vl);
                    }
                    for (k_x = kx_start_b; k_x < kx_end_b; k_x++)
                    {
                        const q7_t *ptrB = row_base + (long)k_x * in_tensor_ch;
                        vint8m4_t vInB = __riscv_vle8_v_i8m4(ptrB, vl);
                        vMaxB = __riscv_vmax(vInB, vMaxB, vl);
                    }
                }

                __riscv_vse8(out_a + cur_ch, vMaxA, vl);
                __riscv_vse8(out_b + cur_ch, vMaxB, vl);
                cur_ch += vl;
                remaining -= vl;
            }
        }

        /* Handle odd last pixel */
        if (out_x < out_tensor_dim)
        {
            long in_x = (long)out_x * stride - pad;
            long kx_start = MAX(0, in_x);
            long kx_end   = MIN(in_tensor_dim, in_x + ker_dim);

            long cur_ch = 0;
            long remaining = in_tensor_ch;
            q7_t *out_ptr = out_tensor + (long)out_x * in_tensor_ch;

            while (remaining > 0)
            {
